import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  GitCheckConnectionSchema,
  GitGenerateKeySchema,
  GitReadPublicKeySchema,
  GitReadPrivateKeySchema,
  GitConfigureSSHSchema,
  GitDetectFrameworkSchema,
  GitListSSHKeysSchema,
  GitFetchBranchesSchema,
  GitListServerKeysSchema,
  GitTestKeyConnectionSchema,
  GitDeleteServerKeySchema,
  GitRenameServerKeySchema,
  CreateGitAccountSchema,
  UpdateGitAccountSchema,
  ListGitAccountsSchema,
  GitAccountIdSchema,
  GitAccountStatusSchema,
  GitSetDefaultAccountSchema,
  GitGetReposSchema,
  GitBindAppSchema,
  GitAccountMappingsSchema,
  GitCloneWithAccountSchema,
  GitSwitchRepoAccountSchema,
  GitTestSSHKeySchema,
  GitDetectMismatchedReposSchema,
  GitFixRepositoryRemotesSchema,
  ApiResult,
  GitConnectionStatus,
  GitHubRepository,
  FrameworkDetection,
  SSHPublicKey,
  ServerSSHKeyInfo,
  GitAccount,
  GitAccountMapping,
  GitAccountStatusResult,
} from './types';
import { sshService } from '../services/SSHService';
import { gitAccountService } from '../services/GitAccountService';
import { githubActionsService } from '../services/GitHubActionsService';
import { queries } from '../db';

export function registerGitHandlers() {
  // Check GitHub SSH connection status
  ipcMain.handle(IPC_CHANNELS.GIT_CHECK_CONNECTION, async (_event, input): Promise<ApiResult<GitConnectionStatus>> => {
    try {
      const { serverId } = GitCheckConnectionSchema.parse(input);

      // Execute ssh with options to bypass host key verification prompts
      // -o StrictHostKeyChecking=no: Skip the "Are you sure?" prompt
      // -T: Disable pseudo-terminal allocation
      // -v: Verbose output for debugging
      const result = await sshService.executeCommand(
        serverId,
        'ssh -o StrictHostKeyChecking=no -vT git@github.com 2>&1 || true'
      );

      const output = result.stdout + result.stderr;

      // Parse the output to determine configuration status
      const isConfigured = output.includes('successfully authenticated');

      // Extract username if authenticated
      let username: string | undefined;
      const usernameMatch = output.match(/Hi ([^!]+)!/);
      if (usernameMatch) {
        username = usernameMatch[1];
      }

      // Extract key path if present
      let keyPath: string | undefined;
      const keyPathMatch = output.match(/identity file ([^\s]+)/);
      if (keyPathMatch) {
        keyPath = keyPathMatch[1];
      }

      const connectionStatus: GitConnectionStatus = {
        isConfigured,
        username,
        keyPath,
        rawOutput: output,
      };

      // Save status to database for caching
      queries.saveGitConnectionStatus({
        serverId,
        isConfigured,
        username,
        keyPath,
        rawOutput: output,
      });

      return {
        success: true,
        data: connectionStatus,
      };
    } catch (error) {
      console.error('Error checking GitHub connection:', error);
      return { success: false, error: String(error) };
    }
  });

  // Generate SSH key on VPS
  ipcMain.handle(IPC_CHANNELS.GIT_GENERATE_KEY, async (_event, input): Promise<ApiResult<{ publicKey: string; keyPath: string }>> => {
    try {
      const { serverId, keyName } = GitGenerateKeySchema.parse(input);

      // Count existing github-vps keys to generate unique name
      const countResult = await sshService.executeCommand(
        serverId,
        'ls ~/.ssh/github-vps* 2>/dev/null | wc -l || echo 0'
      );
      const count = parseInt(countResult.stdout.trim()) || 0;

      // Determine key name
      const finalKeyName = keyName || (count === 0 ? 'github-vps' : `github-vps-${Math.floor(count / 2) + 1}`);
      const keyPath = `~/.ssh/${finalKeyName}`;

      // Remove any existing key with the same name to avoid interactive prompts
      await sshService.executeCommand(
        serverId,
        `rm -f ${keyPath} ${keyPath}.pub && ssh-keygen -q -o -t ed25519 -C "vps@github" -f ${keyPath} -N ""`
      );

      // Set proper permissions
      const chmodCmd = `chmod 600 ${keyPath} && chmod 644 ${keyPath}.pub`;
      await sshService.executeCommand(serverId, chmodCmd);

      // Read the public key
      const readKeyResult = await sshService.executeCommand(serverId, `cat ${keyPath}.pub`);
      const publicKey = readKeyResult.stdout.trim();

      return {
        success: true,
        data: {
          publicKey,
          keyPath,
        },
      };
    } catch (error) {
      console.error('Error generating SSH key:', error);
      return { success: false, error: String(error) };
    }
  });

  // Read public key content
  ipcMain.handle(IPC_CHANNELS.GIT_READ_PUBLIC_KEY, async (_event, input): Promise<ApiResult<{ content: string }>> => {
    try {
      const { serverId, keyPath } = GitReadPublicKeySchema.parse(input);

      const result = await sshService.executeCommand(serverId, `cat ${keyPath}.pub`);

      return {
        success: true,
        data: {
          content: result.stdout.trim(),
        },
      };
    } catch (error) {
      console.error('Error reading public key:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_READ_PRIVATE_KEY, async (_event, input): Promise<ApiResult<{ content: string }>> => {
    try {
      const { serverId, keyPath } = GitReadPrivateKeySchema.parse(input);

      // Security: Read private key (this is sensitive!)
      const result = await sshService.executeCommand(serverId, `cat ${keyPath}`);

      return {
        success: true,
        data: {
          content: result.stdout.trim(),
        },
      };
    } catch (error) {
      console.error('Error reading private key:', error);
      return { success: false, error: String(error) };
    }
  });

  // Configure SSH config file for GitHub
  ipcMain.handle(IPC_CHANNELS.GIT_CONFIGURE_SSH, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { serverId, keyPath } = GitConfigureSSHSchema.parse(input);

      // Create ~/.ssh directory if it doesn't exist
      await sshService.executeCommand(serverId, 'mkdir -p ~/.ssh');

      // Add GitHub's host key to known_hosts to avoid host key verification failure
      // Remove any existing GitHub entries to avoid duplicates, then add fresh ones
      await sshService.executeCommand(serverId, 'ssh-keygen -R github.com 2>/dev/null || true');
      await sshService.executeCommand(serverId, 'ssh-keyscan -H github.com >> ~/.ssh/known_hosts 2>/dev/null');

      // Set proper permissions for known_hosts
      await sshService.executeCommand(serverId, 'chmod 600 ~/.ssh/known_hosts 2>/dev/null || true');

      // Check if config file exists
      const checkConfigResult = await sshService.executeCommand(serverId, 'test -f ~/.ssh/config && echo "exists" || echo "not exists"');
      const configExists = checkConfigResult.stdout.trim() === 'exists';

      // Check if GitHub config already exists
      let githubConfigExists = false;
      if (configExists) {
        const checkGithubResult = await sshService.executeCommand(serverId, 'grep -q "Host github.com" ~/.ssh/config && echo "exists" || echo "not exists"');
        githubConfigExists = checkGithubResult.stdout.trim() === 'exists';
      }

      if (githubConfigExists) {
        // Update existing GitHub config
        const updateCmd = `sed -i '/Host github.com/,/^$/c\\
Host github.com\\
  HostName github.com\\
  User git\\
  IdentityFile ${keyPath}\\
  IdentitiesOnly yes\\
' ~/.ssh/config`;
        await sshService.executeCommand(serverId, updateCmd);
      } else {
        // Append new GitHub config
        const appendCmd = `cat >> ~/.ssh/config << 'EOF'

Host github.com
  HostName github.com
  User git
  IdentityFile ${keyPath}
  IdentitiesOnly yes
EOF`;
        await sshService.executeCommand(serverId, appendCmd);
      }

      // Set proper permissions
      await sshService.executeCommand(serverId, 'chmod 600 ~/.ssh/config');

      // Test the connection (with StrictHostKeyChecking=no to avoid prompts)
      await sshService.executeCommand(serverId, 'ssh -o StrictHostKeyChecking=no -T git@github.com 2>&1 || true');

      return { success: true };
    } catch (error) {
      console.error('Error configuring SSH:', error);
      return { success: false, error: String(error) };
    }
  });

  // Detect framework from repository
  ipcMain.handle(IPC_CHANNELS.GIT_DETECT_FRAMEWORK, async (_event, input): Promise<ApiResult<FrameworkDetection>> => {
    try {
      const { serverId, repoUrl, branch } = GitDetectFrameworkSchema.parse(input);

      const detection = await gitAccountService.detectFramework(serverId, repoUrl, branch || 'main');

      return {
        success: true,
        data: detection,
      };
    } catch (error) {
      console.error('Error detecting framework:', error);
      return { success: false, error: String(error) };
    }
  });

  // List SSH public keys
  ipcMain.handle(IPC_CHANNELS.GIT_LIST_SSH_KEYS, async (_event, input): Promise<ApiResult<SSHPublicKey[]>> => {
    try {
      const { serverId } = GitListSSHKeysSchema.parse(input);

      const keys = await gitAccountService.listSSHKeys(serverId);

      return {
        success: true,
        data: keys,
      };
    } catch (error) {
      console.error('Error listing SSH keys:', error);
      return { success: false, error: String(error) };
    }
  });

  // Fetch available branches from a deployed app's repository
  ipcMain.handle(IPC_CHANNELS.GIT_FETCH_BRANCHES, async (_event, input): Promise<ApiResult<string[]>> => {
    try {
      const { serverId, appName, workingDirectory: providedWorkingDirectory } = GitFetchBranchesSchema.parse(input);

      // Get working directory from either the provided parameter or GitHub Actions config
      let workingDirectory = providedWorkingDirectory;

      if (!workingDirectory) {
        // Fall back to GitHub Actions config if working directory not provided
        const githubActionsConfig = githubActionsService.getConfig(serverId, appName);
        workingDirectory = githubActionsConfig?.working_directory || undefined;
      }

      if (!workingDirectory) {
        return {
          success: false,
          error: 'Working directory not provided and deployment not configured',
        };
      }

      // Fetch all branches and parse the output
      const fetchResult = await sshService.executeCommand(
        serverId,
        `cd ${workingDirectory} && git fetch --all 2>&1`
      );

      if (fetchResult.exitCode !== 0 && !fetchResult.stdout.toLowerCase().includes('fetching')) {
        // Fetch might fail but we can still proceed with listing branches
        console.warn('Git fetch had issues:', fetchResult.stderr);
      }

      // Get all branches (both local and remote)
      const branchResult = await sshService.executeCommand(
        serverId,
        `cd ${workingDirectory} && git branch -a 2>&1`
      );

      if (branchResult.exitCode !== 0) {
        return {
          success: false,
          error: `Failed to list branches: ${branchResult.stderr}`,
        };
      }

      // Parse branch names from the output
      const branches = branchResult.stdout
        .split('\n')
        .map((line) => line.trim())
        .filter((line) => line.length > 0)
        // Remove git markers (* for current branch, + for checked out in worktree)
        .map((line) => {
          // Handle lines like "* main", "+ feat/new-feature", "  remotes/origin/main"
          let branchName = line.replace(/^[\*\+\s]+/, '').trim();
          // Remove remotes/ prefix to show cleaner branch names
          if (branchName.startsWith('remotes/origin/')) {
            branchName = branchName.replace('remotes/origin/', '');
          }
          return branchName;
        })
        // Remove duplicates (same branch might appear as both local and remote)
        .filter((branch, index, arr) => index === arr.indexOf(branch))
        // Filter out HEAD reference
        .filter((branch) => branch !== 'HEAD' && !branch.endsWith('-> origin/main'));

      return {
        success: true,
        data: branches.sort(),
      };
    } catch (error) {
      console.error('Error fetching branches:', error);
      return { success: false, error: String(error) };
    }
  });

  // List SSH keys on the remote server
  ipcMain.handle(IPC_CHANNELS.GIT_LIST_SERVER_KEYS, async (_event, input): Promise<ApiResult<ServerSSHKeyInfo[]>> => {
    try {
      const { serverId } = GitListServerKeysSchema.parse(input);

      // List all private keys in ~/.ssh directory
      const listKeysCmd = `find ~/.ssh -maxdepth 1 -type f ! -name "*.pub" ! -name "config" ! -name "known_hosts*" ! -name "authorized_keys*" 2>/dev/null || true`;
      const result = await sshService.executeCommand(serverId, listKeysCmd);

      const keyPaths = result.stdout
        .split('\n')
        .map((line) => line.trim())
        .filter((line) => line.length > 0);

      const keys: ServerSSHKeyInfo[] = [];

      // Get fingerprint and type for each key
      for (const keyPath of keyPaths) {
        const basename = keyPath.split('/').pop() || keyPath;

        // Try to get fingerprint
        const fingerprintResult = await sshService.executeCommand(
          serverId,
          `ssh-keygen -lf ${keyPath} 2>/dev/null || echo ""`
        );

        let fingerprint: string | undefined;
        let type: string | undefined;

        if (fingerprintResult.stdout.trim()) {
          // Parse output like: "2048 SHA256:xxx... user@host (RSA)"
          const match = fingerprintResult.stdout.match(/^\d+\s+([^\s]+)\s+.*?\(([^)]+)\)/);
          if (match) {
            fingerprint = match[1];
            type = match[2];
          }
        }

        keys.push({
          name: basename,
          path: keyPath,
          fingerprint,
          type,
        });
      }

      return {
        success: true,
        data: keys,
      };
    } catch (error) {
      console.error('Error listing server SSH keys:', error);
      return { success: false, error: String(error) };
    }
  });

  // Test GitHub connection with a specific SSH key
  ipcMain.handle(IPC_CHANNELS.GIT_TEST_KEY_CONNECTION, async (_event, input): Promise<ApiResult<GitConnectionStatus>> => {
    try {
      const { serverId, keyPath } = GitTestKeyConnectionSchema.parse(input);

      // Test connection with specific key using ssh -i flag
      // -i: Specify identity file (private key)
      // -o StrictHostKeyChecking=no: Skip host key verification prompt
      // -o IdentitiesOnly=yes: Only use the specified key
      // -T: Disable pseudo-terminal allocation
      // -v: Verbose output for debugging
      const testCmd = `ssh -i ${keyPath} -o StrictHostKeyChecking=no -o IdentitiesOnly=yes -vT git@github.com 2>&1 || true`;
      const result = await sshService.executeCommand(serverId, testCmd);

      const output = result.stdout + result.stderr;

      // Parse the output to determine configuration status
      const isConfigured = output.includes('successfully authenticated');

      // Extract username if authenticated
      let username: string | undefined;
      const usernameMatch = output.match(/Hi ([^!]+)!/);
      if (usernameMatch) {
        username = usernameMatch[1];
      }

      const connectionStatus: GitConnectionStatus = {
        isConfigured,
        username,
        keyPath,
        rawOutput: output,
      };

      // Save status to database if configured successfully
      if (isConfigured) {
        queries.saveGitConnectionStatus({
          serverId,
          isConfigured,
          username,
          keyPath,
          rawOutput: output,
        });
      }

      return {
        success: true,
        data: connectionStatus,
      };
    } catch (error) {
      console.error('Error testing key connection:', error);
      return { success: false, error: String(error) };
    }
  });

  // Delete SSH key from the remote server
  ipcMain.handle(IPC_CHANNELS.GIT_DELETE_SERVER_KEY, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { serverId, keyPath } = GitDeleteServerKeySchema.parse(input);

      // Delete both private and public keys
      const deleteCmd = `rm -f ${keyPath} ${keyPath}.pub`;
      await sshService.executeCommand(serverId, deleteCmd);

      return {
        success: true,
      };
    } catch (error) {
      console.error('Error deleting SSH key:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_RENAME_SERVER_KEY, async (_event, input): Promise<ApiResult<{ newPath: string }>> => {
    try {
      const { serverId, oldPath, newName } = GitRenameServerKeySchema.parse(input);

      // Validate new name (no path separators, no special characters)
      if (newName.includes('/') || newName.includes('..') || newName.startsWith('.')) {
        throw new Error('Invalid key name');
      }

      // Get directory from old path
      const directory = oldPath.substring(0, oldPath.lastIndexOf('/'));
      const newPath = `${directory}/${newName}`;

      // Check if target already exists
      const checkCmd = `test -f ${newPath} && echo "exists" || echo "ok"`;
      const checkResult = await sshService.executeCommand(serverId, checkCmd);
      if (checkResult.stdout.trim() === 'exists') {
        throw new Error('A key with this name already exists');
      }

      // Rename both private and public keys
      const renameCmd = `mv ${oldPath} ${newPath} && mv ${oldPath}.pub ${newPath}.pub`;
      await sshService.executeCommand(serverId, renameCmd);

      return {
        success: true,
        data: { newPath },
      };
    } catch (error) {
      console.error('Error renaming SSH key:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  // --- Multi-account Git handlers ---
  ipcMain.handle(IPC_CHANNELS.GIT_CREATE_ACCOUNT, async (_event, input): Promise<ApiResult<GitAccount>> => {
    try {
      const payload = CreateGitAccountSchema.parse(input);
      const account = await gitAccountService.createAccount(payload);
      return { success: true, data: account };
    } catch (error) {
      console.error('Error creating Git account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_UPDATE_ACCOUNT, async (_event, input): Promise<ApiResult<GitAccount>> => {
    try {
      const payload = UpdateGitAccountSchema.parse(input);
      const account = await gitAccountService.updateAccount(payload);
      return { success: true, data: account };
    } catch (error) {
      console.error('Error updating Git account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_LIST_ACCOUNTS, async (_event, input): Promise<ApiResult<GitAccount[]>> => {
    try {
      const payload = ListGitAccountsSchema.parse(input);
      const accounts = await gitAccountService.listAccounts(payload.serverId, payload.provider);
      return { success: true, data: accounts };
    } catch (error) {
      console.error('Error listing Git accounts:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_DELETE_ACCOUNT, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const payload = GitAccountIdSchema.parse(input);
      await gitAccountService.deleteAccount(payload.accountId);
      return { success: true };
    } catch (error) {
      console.error('Error deleting Git account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_REVOKE_ACCOUNT, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const payload = GitAccountIdSchema.parse(input);
      await gitAccountService.revokeAccess(payload.accountId);
      return { success: true };
    } catch (error) {
      console.error('Error revoking Git account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(
    IPC_CHANNELS.GIT_CHECK_ACCOUNT_STATUS,
    async (_event, input): Promise<ApiResult<GitAccountStatusResult>> => {
      try {
        const payload = GitAccountStatusSchema.parse(input);
        const result = await gitAccountService.checkAccountStatus(payload.accountId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error checking Git account status:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.GIT_TEST_SSH_KEY,
    async (_event, input): Promise<ApiResult<{ isValid: boolean; message: string; username?: string }>> => {
      try {
        const payload = GitTestSSHKeySchema.parse(input);
        const result = await gitAccountService.testSSHKey(payload.serverId, payload.accountId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error testing SSH key:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.GIT_DETECT_MISMATCHED_REPOS,
    async (_event, input): Promise<ApiResult<{ mismatchedRepos: Array<{ path: string; currentUrl: string; expectedUrl: string }>; totalScanned: number }>> => {
      try {
        const payload = GitDetectMismatchedReposSchema.parse(input);
        const result = await gitAccountService.detectMismatchedRepositories(payload.serverId, payload.accountId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error detecting mismatched repositories:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.GIT_FIX_REPOSITORY_REMOTES,
    async (_event, input): Promise<ApiResult<{ fixed: number; failed: Array<{ path: string; error: string }> }>> => {
      try {
        const payload = GitFixRepositoryRemotesSchema.parse(input);
        const result = await gitAccountService.fixRepositoryRemotes(payload.serverId, payload.accountId, payload.repoPaths);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error fixing repository remotes:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.GIT_SET_DEFAULT_ACCOUNT,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const payload = GitSetDefaultAccountSchema.parse(input);
        await gitAccountService.setDefaultAccount(payload.serverId, payload.gitAccountId);
        return { success: true };
      } catch (error) {
        console.error('Error setting default Git account:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(IPC_CHANNELS.GIT_GET_REPOS, async (_event, input): Promise<ApiResult<GitHubRepository[]>> => {
    try {
      const payload = GitGetReposSchema.parse(input);
      const repos = await gitAccountService.getRepositories(payload.gitAccountId, payload.page ?? 1, payload.perPage ?? 30);
      return { success: true, data: repos };
    } catch (error) {
      console.error('Error fetching repositories for account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_BIND_APP, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const payload = GitBindAppSchema.parse(input);
      await gitAccountService.bindApp(payload);
      return { success: true };
    } catch (error) {
      console.error('Error binding Git account to app:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(
    IPC_CHANNELS.GIT_GET_ACCOUNT_MAPPINGS,
    async (_event, input): Promise<ApiResult<GitAccountMapping[]>> => {
      try {
        const payload = GitAccountMappingsSchema.parse(input);
        const mappings = await gitAccountService.getAccountMappings(payload.serverId);
        return { success: true, data: mappings };
      } catch (error) {
        console.error('Error loading Git account mappings:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(IPC_CHANNELS.GIT_CLONE_WITH_ACCOUNT, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const payload = GitCloneWithAccountSchema.parse(input);
      await gitAccountService.cloneWithAccount(
        payload.serverId,
        payload.gitAccountId,
        payload.repository,
        payload.targetPath,
        payload.branch
      );
      return { success: true };
    } catch (error) {
      console.error('Error cloning repository with Git account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.GIT_SWITCH_REPO_ACCOUNT, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const payload = GitSwitchRepoAccountSchema.parse(input);
      await gitAccountService.switchRepoAccount(
        payload.serverId,
        payload.repoPath,
        payload.gitAccountId,
        payload.repository
      );
      return { success: true };
    } catch (error) {
      console.error('Error switching repository account:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });
}
